#include <iostream>
#include <vector>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    vector<int> a(N);
    for (int i = 0; i < N; ++i) {
        cin >> a[i];
    }

    int remove_idx;
    cin >> remove_idx;
    // convert to 0-based
    remove_idx--;

    int insert_idx, value;
    cin >> insert_idx >> value;
    // convert to 0-based (index in the array after removal)
    insert_idx--;

    // Remove element at remove_idx: shift left
    for (int i = remove_idx; i < N - 1; ++i) {
        a[i] = a[i + 1];
    }
    // Now array has size N-1
    // Insert at insert_idx: shift right from the end
    // Resize to accommodate the new element
    a.resize(N);
    for (int i = N - 1; i > insert_idx; --i) {
        a[i] = a[i - 1];
    }
    a[insert_idx] = value;

    for (int i = 0; i < N; ++i) {
        if (i > 0) cout << ' ';
        cout << a[i];
    }
    cout << '\n';

    return 0;
}
